module.m4.body:
تُعرّف أوامر DDL هيكل قاعدة البيانات.

CREATE TABLE تُضيف جدولاً جديداً بتعريفات الأعمدة:
CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT);

ALTER TABLE تُضيف أعمدة أو تحذفها من جدول موجود:
ALTER TABLE users ADD COLUMN email TEXT;

DROP TABLE تحذف جدولاً وجميع بياناته بصفة دائمة:
DROP TABLE users;

module.m7.body:
تساعد الاستعلامات الفرعية على التصفية بمجموعات محسوبة أو قيم فردية.

IN: مطابقة الصفوف حيث يكون عمود ضمن نتيجة استعلام فرعي.
SELECT name FROM customers WHERE id IN (SELECT customer_id FROM orders);

قياسي: المقارنة بقيمة محسوبة واحدة.
SELECT name FROM customers WHERE id = (SELECT customer_id FROM orders ORDER BY total DESC LIMIT 1);

EXISTS: يُرجع true إذا وجد الاستعلام الفرعي صفاً واحداً على الأقل.
SELECT name FROM customers WHERE EXISTS (SELECT 1 FROM orders WHERE orders.customer_id = customers.id);
